     */
    func planSessionReconnect(sessionId: Data, attempt: UInt32, authenticationStopped: Bool) throws  -> BridgeReconnectPlan
    
    /**
     * Pumps driver updates for `operation_id` until a terminal fact or no pending work.
     */
