    func renameProfileGroup(oldName: String, newName: String) throws  -> UInt32
    
    func reorderProfiles(group: String?, ordered: [BridgeProfileOrderItem]) throws 
    
    /**
     * Drop a review token without authorizing (operator discard).
     */
