/**
 * Typed bridge failures. Messages never include SQL, credentials, or cell values.
 */
public 
enum BridgeError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    /**
     * Recoverable rejection (validation, capacity, unknown id, stale revision).
     */
    case Rejected(code: String, message: String
    )
    /**
     * A Rust panic was caught at the facade boundary; process remains usable.
     */
    case ContainedPanic(message: String
    )
    /**
     * Runtime already stopped or not yet constructed.
     */
    case RuntimeUnavailable
    /**
     * Requested session is not registered.
     */
    case UnknownSession
    /**
     * Requested operation is not registered.
     */
    case UnknownOperation
    /**
     * Requested page is not resident.
     */
    case UnknownPage
    /**
     * Event cursor is in the future of the producer.
     */
    case FutureCursor
    /**
     * Event cursor requires resync (gap or retired producer).
     */
    case ResyncRequired
    /**
     * Facade has begun or completed shutdown.
     */
    case ShuttingDown

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension BridgeError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeBridgeError: FfiConverterRustBuffer {
    typealias SwiftType = BridgeError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> BridgeError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Rejected(
            code: try FfiConverterString.read(from: &buf), 
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .ContainedPanic(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .RuntimeUnavailable
        case 4: return .UnknownSession
        case 5: return .UnknownOperation
        case 6: return .UnknownPage
        case 7: return .FutureCursor
        case 8: return .ResyncRequired
        case 9: return .ShuttingDown

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: BridgeError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Rejected(code,message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(code, into: &buf)
            FfiConverterString.write(message, into: &buf)
            
        
        case let .ContainedPanic(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        
        case .RuntimeUnavailable:
            writeInt(&buf, Int32(3))
        
        
        case .UnknownSession:
            writeInt(&buf, Int32(4))
        
        
        case .UnknownOperation:
            writeInt(&buf, Int32(5))
        
        
        case .UnknownPage:
            writeInt(&buf, Int32(6))
        
        
        case .FutureCursor:
            writeInt(&buf, Int32(7))
        
        
        case .ResyncRequired:
            writeInt(&buf, Int32(8))
        
        
        case .ShuttingDown:
            writeInt(&buf, Int32(9))
        
        }
    }
}


